func (fr *FacetRequest) Validate() error {
    if fr == nil {
        return nil
    }
    nrCount := len(fr.NumericRanges)
    // Only skip numeric-range validation when there are no numeric ranges.
    if nrCount == 0 {
        return nil
    }

    // validate numeric ranges
    seen := map[string]struct{}{}
    for i, nr := range fr.NumericRanges {
        if nr == nil {
            return fmt.Errorf("numeric range %d is nil", i)
        }
        if nr.Name == "" {
            return fmt.Errorf("numeric range %d missing name", i)
        }
        if nr.Min == nil && nr.Max == nil {
            return fmt.Errorf("numeric range %s missing both min and max", nr.Name)
        }
        // if both present, ensure min <= max
        if nr.Min != nil && nr.Max != nil && *nr.Min > *nr.Max {
            return fmt.Errorf("numeric range %s min > max", nr.Name)
        }
        if _, ok := seen[nr.Name]; ok {
            return fmt.Errorf("duplicate numeric range name %s", nr.Name)
        }
        seen[nr.Name] = struct{}{}
    }

    return nil
}
